DROP TABLE IF EXISTS `operation_log`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `operation_log` (
  `log_id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '日志ID',
  `user_id` bigint unsigned NOT NULL COMMENT '操作用户ID',
  `operation` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT '操作类型',
  `target_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT '操作对象类型：CONTRACT合同/USER用户/RISK_REPORT风险报告等',
  `target_id` bigint unsigned DEFAULT NULL COMMENT '操作对象ID',
  `ip` varchar(45) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT '操作来源IP地址',
  `result` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT '操作结果：SUCCESS成功/FAIL失败',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '操作时间',
  `before_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_bin COMMENT 'before content',
  `after_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_bin COMMENT 'after content',
  PRIMARY KEY (`log_id`),
  KEY `idx_audit_composite` (`user_id`,`operation`,`created_at`),
  CONSTRAINT `fk_operation_user` FOREIGN KEY (`user_id`) REFERENCES `user_info` (`user_id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=441 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin COMMENT='操作日志表';
